SELECT id, product_name, product_model_number, company_number, compatibility_status, paper_type, notice_ids, created_at, updated_at FROM post_processing_print_uv
AND product_name = #{productName}
AND product_model_number = #{productModelNumber}
AND company_number = #{companyNumber}
ORDER BY product_name, product_model_number, company_number

SELECT id, product_name, product_model_number, company_number, compatibility_status, paper_type, notice_ids, created_at, updated_at FROM post_processing_print_uv WHERE product_name = #{productName}
AND company_number = #{companyNumber}
AND ( (product_model_number = #{productModelNumber} AND product_model_number IS NOT NULL AND product_model_number != '') )
AND (product_model_number IS NULL OR product_model_number = '')
AND paper_type = #{paperType}
AND (paper_type IS NULL OR paper_type = '')
ORDER BY id DESC LIMIT 1
